import{_ as e,o,c as n,a0 as i}from"./chunks/framework.BWpMpcZ2.js";const p=JSON.parse('{"title":"Endpoints","description":"","frontmatter":{},"headers":[],"relativePath":"configuration/endpoints.md","filePath":"configuration/endpoints.md"}'),d={name:"configuration/endpoints.md"};function a(r,t,s,l,c,h){return o(),n("div",null,[...t[0]||(t[0]=[i('<h1 id="endpoints" tabindex="-1">Endpoints <a class="header-anchor" href="#endpoints" aria-label="Permalink to &quot;Endpoints&quot;">​</a></h1><p>Endpoints connect margin to an AI model. You can use local models (completely private, offline) or cloud APIs.</p><h2 id="active-endpoint" tabindex="-1">Active Endpoint <a class="header-anchor" href="#active-endpoint" aria-label="Permalink to &quot;Active Endpoint&quot;">​</a></h2><p>Select which endpoint margin should use for AI requests:</p><ul><li><strong>.env Default</strong>: Uses settings from your <code>.env</code> file. This is the traditional method and useful if you prefer environment-based configuration.</li><li><strong>Custom endpoints</strong>: Any endpoint you&#39;ve added via the UI.</li></ul><h2 id="adding-an-endpoint" tabindex="-1">Adding an Endpoint <a class="header-anchor" href="#adding-an-endpoint" aria-label="Permalink to &quot;Adding an Endpoint&quot;">​</a></h2><ol><li><p>Fill in the <strong>Add New Endpoint</strong> form:</p><table tabindex="0"><thead><tr><th>Field</th><th>Description</th></tr></thead><tbody><tr><td><strong>Name</strong></td><td>A label for this endpoint (e.g., &quot;Ollama&quot;, &quot;OpenAI&quot;, &quot;My Local Model&quot;).</td></tr><tr><td><strong>Base URL</strong></td><td>The full URL of your API (e.g., <code>http://localhost:11434/v1</code>, <code>https://api.openai.com/v1</code>).</td></tr><tr><td><strong>API Key</strong></td><td>Your API key (required for cloud providers, optional for local).</td></tr><tr><td><strong>Model</strong></td><td>The model name (e.g., <code>gpt-4o</code>, <code>qwen2.5-coder</code>). Optional -- some endpoints auto-detect.</td></tr><tr><td><strong>Context Window</strong></td><td>The maximum context size in tokens (default: 8192).</td></tr><tr><td><strong>Thinking Model</strong></td><td>When enabled (default), inline reasoning tags (e.g. <code>&lt;think&gt;</code>, <code>&lt;|channel|&gt;</code>) are stripped from the response. Disable to see the raw output including any tags the model emits.</td></tr></tbody></table><p>When <strong>Thinking Model</strong> is checked, a <strong>Custom Thinking Tags</strong> section appears where you can add open/close tag pairs for models with non-standard reasoning tags.</p></li><li><p>Click <strong>Test Connection</strong> to verify the endpoint works.</p></li><li><p>Click <strong>Save Endpoint</strong>.</p></li></ol><h3 id="common-local-endpoints" tabindex="-1">Common Local Endpoints <a class="header-anchor" href="#common-local-endpoints" aria-label="Permalink to &quot;Common Local Endpoints&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Provider</th><th>Default URL</th><th>Default Port</th></tr></thead><tbody><tr><td>Ollama</td><td><code>http://localhost:11434</code></td><td>11434</td></tr><tr><td>LM Studio</td><td><code>http://localhost:1234/v1</code></td><td>1234</td></tr></tbody></table><h3 id="cloud-providers" tabindex="-1">Cloud Providers <a class="header-anchor" href="#cloud-providers" aria-label="Permalink to &quot;Cloud Providers&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Provider</th><th>Base URL</th></tr></thead><tbody><tr><td>OpenAI</td><td><code>https://api.openai.com/v1</code></td></tr><tr><td>Anthropic</td><td><code>https://api.anthropic.com/v1</code></td></tr><tr><td>Google Gemini</td><td><code>https://generativelanguage.googleapis.com/v1beta</code></td></tr><tr><td>Grok (xAI)</td><td><code>https://api.x.ai/v1</code></td></tr><tr><td>OpenRouter</td><td><code>https://openrouter.ai/api/v1</code></td></tr><tr><td>Groq</td><td><code>https://api.groq.com/openai/v1</code></td></tr></tbody></table><blockquote><p>All cloud providers require an API key. You can get one from their respective console or dashboard.</p></blockquote><div class="tip custom-block"><p class="custom-block-title">API keys are stored locally in <code>settings.json</code> and never sent anywhere except to the endpoint you configure. No data leaves your machine unless you explicitly connect to a cloud provider.</p></div><h2 id="reasoning-settings" tabindex="-1">Reasoning Settings <a class="header-anchor" href="#reasoning-settings" aria-label="Permalink to &quot;Reasoning Settings&quot;">​</a></h2><p>Many models produce internal reasoning before generating their final output. margin can detect and separate this reasoning text from the visible response.</p><h3 id="thinking-model-toggle" tabindex="-1">Thinking Model Toggle <a class="header-anchor" href="#thinking-model-toggle" aria-label="Permalink to &quot;Thinking Model Toggle&quot;">​</a></h3><p>Each endpoint has a <strong>Thinking Model</strong> checkbox. It controls how inline reasoning tags in the <code>content</code> field are handled:</p><ul><li><strong>On (default)</strong>: Inline tags like <code>&lt;think&gt;</code>, <code>&lt;\\|channel\\|&gt;</code>, and custom tag pairs are stripped from the prose output. The reasoning text is captured and shown in the &quot;Thought Process&quot; dropdown instead.</li><li><strong>Off</strong>: Tags pass through as raw text — you&#39;ll see <code>&lt;think&gt;...&lt;/think&gt;</code> or <code>&lt;|channel|&gt;...&lt;/channel|&gt;</code> directly in the editor output.</li></ul><p>Some models (including LM Studio, DeepSeek, and some OpenAI-compatible providers) use a separate <code>reasoning_content</code> field in the API response rather than inline tags. This reasoning text is always captured in the &quot;Thought Process&quot; dropdown regardless of the toggle — the toggle only controls tag stripping from the main content stream.</p><h3 id="custom-thinking-tags" tabindex="-1">Custom Thinking Tags <a class="header-anchor" href="#custom-thinking-tags" aria-label="Permalink to &quot;Custom Thinking Tags&quot;">​</a></h3><p>Different models use different tags to delimit their reasoning. margin supports these out of the box:</p><table tabindex="0"><thead><tr><th>Opening</th><th>Closing</th></tr></thead><tbody><tr><td><code>&lt;|channel|&gt;</code></td><td><code>&lt;channel|&gt;</code>, <code>&lt;|channel|&gt;</code>, <code>&lt;/channel|&gt;</code>, <code>|channel|&gt;</code></td></tr><tr><td><code>&lt;think&gt;</code></td><td><code>&lt;/think&gt;</code></td></tr></tbody></table><p>If your model uses non-standard tags (e.g., <code>[REASONING]...[/REASONING]</code>), add them in the endpoint form:</p><ol><li>Open the endpoint for editing.</li><li>Check <strong>Thinking Model</strong>.</li><li>Under <strong>Custom Thinking Tags</strong>, enter the opening tag (e.g., <code>[REASONING]</code>) and closing tag (e.g., <code>[/REASONING]</code>).</li><li>Click <strong>Add Tag</strong> — it appears as a removable chip.</li><li>Save the endpoint.</li></ol><p>Multiple custom tag pairs are supported. Added tags are stripped alongside the built-in defaults.</p><h3 id="prepend-thinking-preamble" tabindex="-1">Prepend Thinking Preamble <a class="header-anchor" href="#prepend-thinking-preamble" aria-label="Permalink to &quot;Prepend Thinking Preamble&quot;">​</a></h3><p>When enabled, this injects a system prompt that instructs the model to use reasoning tags before every response. Useful for models that can reason internally but don&#39;t do it by default.</p><h3 id="finding-your-model-s-tags" tabindex="-1">Finding Your Model&#39;s Tags <a class="header-anchor" href="#finding-your-model-s-tags" aria-label="Permalink to &quot;Finding Your Model&#39;s Tags&quot;">​</a></h3><p>If you see raw tags like <code>&lt;think&gt;...</code> or <code>&lt;|channel|&gt;...</code> in your output, the model is using reasoning tags that aren&#39;t being filtered. Check your endpoint&#39;s <strong>Thinking Model</strong> toggle and add any missing custom tags. If the toggle is on and you still see tags, add them as custom tags.</p><blockquote><p>See <a href="./../ai-assist.html#reasoning-amp-thinking">AI Assist &gt; Reasoning &amp; Thinking</a> for how reasoning appears in the editor.</p></blockquote><h2 id="editing-and-deleting-endpoints" tabindex="-1">Editing and Deleting Endpoints <a class="header-anchor" href="#editing-and-deleting-endpoints" aria-label="Permalink to &quot;Editing and Deleting Endpoints&quot;">​</a></h2><ul><li><strong>Edit</strong>: Click the pencil icon on an endpoint card to modify its settings.</li><li><strong>Delete</strong>: Click the trash icon to remove an endpoint.</li></ul>',32)])])}const u=e(d,[["render",a]]);export{p as __pageData,u as default};
